// Groq returns OpenAI format: response.choices[0].message.content
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';

if (!content) {
  return [{ json: { keywords: [], error: 'No response from Groq' } }];
}

// Extract JSON array from response
const jsonMatch = content.match(/\[[\s\S]*?\]/);
let keywords = [];

if (jsonMatch) {
  try {
    keywords = JSON.parse(jsonMatch[0]);
  } catch(e) {
    // Fallback: split by comma
    keywords = content.replace(/[\[\]"]/g, '').split(',').map(k => k.trim());
  }
}

return [{ json: { keywords: keywords.slice(0, 6) } }];

// Input: 2 items from Merge (Append)
const keywords = $input.all().find(i => i.json.keywords)?.json.keywords || [];
const templates = $input.all().find(i => i.json.templates)?.json.templates || [];

return [{
  json: {
    keywords,
    templates
  }
}];

const memes = $input.first().json.data?.memes || [];
const keywords = ($input.first().json.keywords || []).slice(0, 3).map(k => k.toLowerCase());
const trendingNames = ($input.first().json.trending_template_names || []).map(n => n.toLowerCase());

// 1. Calculate the scores with a random noise factor to ensure we don't get the same memes every time
const scored = memes.map(meme => {
  const name = meme.name.toLowerCase();
  const keywordScore = keywords.filter(k => name.includes(k)).length;
  const trendScore = trendingNames.some(t => {
    const tWords = t.split(' ');
    return tWords.some(w => w.length > 4 && name.includes(w));
  }) ? 1 : 0;
  const randomNoise = Math.random() * 1.5; // Acts as a 'temperature' to shuffle the top results
  return { ...meme, score: keywordScore + trendScore + randomNoise };
});

// 2. Separate by source to guarantee a balanced mix
const imgflipMemes = scored.filter(m => m.source !== 'qdrant').sort((a,b) => b.score - a.score);
const qdrantMemes = scored.filter(m => m.source === 'qdrant').sort((a,b) => b.score - a.score);

// 3. THE FIX FOR VARIETY: 
// Instead of taking the absolute top 10 every time, we take the top 40 most relevant,
// completely shuffle them, and THEN pick a subset. This forces a massive rotation of templates!
const candidateImgflip = imgflipMemes.slice(0, 40).sort(() => 0.5 - Math.random());
const candidateQdrant = qdrantMemes.slice(0, 20).sort(() => 0.5 - Math.random());

const randomTopImgflip = candidateImgflip.slice(0, 15);
const randomTopQdrant = candidateQdrant.slice(0, 5);

// 4. Combine into a pool of 20 random (but highly relevant) templates
const combinedPool = [...randomTopImgflip, ...randomTopQdrant].sort(() => 0.5 - Math.random());

return [{
  json: {
    templates: combinedPool,
    keywords: keywords
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';
const allMemes = $('Merge_Templates').first().json.data?.memes || [];

const jsonMatch = content.match(/\[[\s\S]*?\]/);

if (!jsonMatch) {
  return [{ json: { selected_templates: [] } }];
}

let selected = [];
try {
  const raw = JSON.parse(jsonMatch[0]);
  selected = raw.map((item) => {
    const idStr = String(item.id || '');
    const found = allMemes.find((t) => String(t.id) === idStr) || {};
    return {
      id:   idStr,
      name: String(item.name || found.name || "Unknown"),
      url:  String(found.url || "")
    };
  });
} catch(err) {
  console.log("Parse error:", String(err));
}

return [{ json: { selected_templates: selected } }];

const input = $('Code in JavaScript5').first().json;

// Get keywords - try multiple sources
const keywords = $('Filter_templet1').first().json.keywords ||
                 $('Code in JavaScript6').first().json.keywords || [];

// Get templates from Filter_templet1
const templates = $json.templates || $('Filter_templet1').first().json.templates || [];

// Get trending Reddit template names for context
const trendingNames = $('Merge_Templates').first().json.trending_template_names || [];

const templatesText = templates
  .map(t => `- "${t.name}" (ID: ${t.id})`)
  .join('\n');

const trendingText = trendingNames.length > 0
  ? `\nCURRENTLY TRENDING TEMPLATE STYLES (use as inspiration):\n${trendingNames.join(', ')}`
  : '';

return {
  json: {
    model: "meta-llama/llama-4-scout-17b-16e-instruct",
    temperature: 1.2,
    messages: [
      {
        role: "system",
        content: "You are a meme template selector. You output ONLY valid JSON arrays, nothing else. No explanation, no markdown."
      },
      {
        role: "user",
        content: `Pick the 10 best meme templates for this brand.\n\nBRAND: ${input.brand_name}\nPRODUCT: ${input.product_or_service}\nAUDIENCE: ${input.target_audience}\nTONE: ${input.tone}\nKEYWORDS: ${keywords.join(', ')}\n${trendingText}\n\nAVAILABLE TEMPLATES:\n${templatesText}\n\nChoose exactly 10 templates that are recognizable to the audience and match the tone.\nIMPORTANT: Prioritize variety — avoid picking the same templates repeatedly.\nPrefer templates that haven't been commonly used for this brand type.\nPick at least a few unexpected/creative templates that still fit the brand.\n\nOUTPUT ONLY THIS JSON ARRAY WITH EXACTLY 10 OBJECTS:\n[\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"},\n  {"id": "<id>", "name": "<name>"}\n]`
      }
    ]
  }
};

const selectedTemplates = $input.all()[0].json.selected_templates || [];

return selectedTemplates.map(t => ({
  json: {
    id: t.id,
    name: t.name,
    reason: t.reason
  }
}));

const raw = $input.first().json;
const originalMemes = $('Enrich_Meme_Output').first().json.memes || [];

let aiResults = [];
try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  const cleaned = content.replace(/```json|```/g, '').trim();
  const parsedObj = JSON.parse(cleaned);
  aiResults = parsedObj.results || parsedObj || [];
  if (!Array.isArray(aiResults)) {
    aiResults = [aiResults];
  }
} catch (e) {
  console.log("Parse error:", e.message);
}

return originalMemes.map((memeData, index) => {
  let jarvis = {};
  try {
    const parsed = aiResults[index] || aiResults[0] || {};
    const p = parsed.parameters || {
        social_currency: 0, triggers: 0, emotion: 0, public_value: 0, practical_value: 0, storytelling: 0,
        visual_familiarity: 0, text_density: 0, sentiment_polarity: 0, subject_prominence: 0,
        visual_hooks: 0, share_friction: 0, relatability_breadth: 0
    };

    const stepps    = (p.social_currency + p.triggers + p.emotion + p.public_value + p.practical_value + p.storytelling) / 6 || 0;
    const cognitive = (p.visual_familiarity + p.text_density + p.sentiment_polarity + p.subject_prominence) / 4 || 0;
    const tipping   = (p.visual_hooks + p.share_friction + p.relatability_breadth) / 3 || 0;
    const virality  = (stepps * 0.50) + (cognitive * 0.25) + (tipping * 0.25) || 0;

    jarvis = {
      parameters: p,
      scores: {
        stepps_score:    Math.round(stepps * 100) / 100,
        cognitive_score: Math.round(cognitive * 100) / 100,
        tipping_score:   Math.round(tipping * 100) / 100,
        virality_score:  Math.round(virality * 100) / 100
      },
      verdict:   virality >= 3.5 ? "VIRAL" : "NOT_VIRAL",
      reasoning: parsed.reasoning || "Failed to evaluate."
    };
  } catch(e) {
    jarvis = { scores: {virality_score: 0, stepps_score: 0, cognitive_score: 0, tipping_score: 0}, verdict: "NOT_VIRAL", parameters: {}, reasoning: "Error" };
  }

  const scores = jarvis.scores;
  return {
    json: {
      status:          scores.virality_score >= 3.5 ? "Approved ✅" : "Low Virality ❌",
      meme_url:        memeData.url           || "",
      page_url:        memeData.page_url      || "",
      template_name:   memeData.template_name || "",
      caption_top:     memeData.text0         || "",
      caption_bottom:  memeData.text1         || "",
      virality_score:  scores.virality_score,
      stepps_score:    scores.stepps_score,
      cognitive_score: scores.cognitive_score,
      tipping_score:   scores.tipping_score,
      verdict:         jarvis.verdict,
      reasoning:       jarvis.reasoning,
      parameters:      jarvis.parameters
    }
  };
});

