const results = $input.first().json.result || [];

// Deduplicate by text
const seen = new Set();
const trends = [];
for (const r of results) {
  const text = r.payload.text;
  if (!seen.has(text)) {
    seen.add(text);
    trends.push(text);
  }
}

return [{
  json: {
    relevant_trends: trends,
    trends_string: trends.join(', ')
  }
}];

// Get Imgflip classics
const imgflipMemes = $('Get_100_templets1').first().json.data?.memes || [];
const imgflipTemplates = imgflipMemes.slice(0, 50).map(m => ({
  id:     m.id,
  name:   m.name,
  url:    m.url,
  box_count: m.box_count,
  source: 'imgflip'
}));

// Get Reddit templates from Qdrant
const qdrantResults = $('Query_Template_Qdrant').first().json.result || [];
const qdrantTemplates = qdrantResults.map(r => ({
  id: String(r.payload?.id || r.payload?.template_id || r.id),
  name: String(r.payload?.name || r.payload?.title || 'Unknown'),
  url: String(r.payload?.url || r.payload?.image_url || r.payload?.template_url || ''),
  box_count: Number(r.payload?.box_count || 2),
  source: 'qdrant'
})).filter(m => m.id && m.id !== 'undefined');

const combinedMemes = [...imgflipTemplates, ...qdrantTemplates];
const redditNames = qdrantResults.map(r => r.payload?.name || '').filter(n => n);

console.log(`Imgflip: ${imgflipTemplates.length} | Qdrant: ${qdrantTemplates.length}`);

return [{
  json: {
    data: {
      memes: combinedMemes
    },
    keywords:              $('Code in JavaScript6').first().json.keywords || [],
    trending_template_names: redditNames
  }
}];

const items = $input.all();
const sourceItems = $('parse_groq').all(); // grab template names + captions from here
const memes = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const source = sourceItems[i]?.json || {};

  if (item.json?.success && item.json?.data?.url) {
    memes.push({
        url:           item.json.data.url,
        page_url:      item.json.data.page_url,
        success:       true,
        template_name: source.template_name || source.name || "",
        text0:         source.text0 || "",
        text1:         source.text1 || ""
    });
  } else if (source.template_url) {
    const texts = [source.text0, source.text1, source.text2, source.text3]
      .map(t => t ? t.trim() : "")
      .filter(t => t !== "");

    let topText = "_";
    let bottomText = "_";

    if (texts.length === 1) {
      topText = texts[0];
    } else if (texts.length === 2) {
      topText = texts[0];
      bottomText = texts[1];
    } else if (texts.length === 3) {
      topText = texts[0];
      bottomText = texts[1] + "~n" + texts[2];
    } else if (texts.length >= 4) {
      topText = texts[0] + "~n" + texts[1];
      bottomText = texts[2] + "~n" + texts[3];
    }

    const t0 = encodeURIComponent(topText);
    const t1 = encodeURIComponent(bottomText);
    const customUrl = `https://api.memegen.link/images/custom/${t0}/${t1}.png?background=${encodeURIComponent(source.template_url)}`;

    memes.push({
        url:           customUrl,
        page_url:      source.template_url,
        success:       true,
        template_name: source.template_name || source.name || "",
        text0:         source.text0 || "",
        text1:         source.text1 || ""
    });
  } else {
    console.log("Skipping failed meme:", JSON.stringify(item.json));
  }
}

return [{ json: { memes } }];

// Pass ALL items through, don't collapse to one
return $input.all().map(item => ({
  json: {
    id:   item.json.id,
    name: item.json.name
  }
}));

